for domain in ~/access-logs/*; do [ -f "$domain" ] || continue; total_hits=$(awk '{print $1}' "$domain" | wc -l); echo -e "Domain: $(basename "$domain")\nTotal IP Hits: $total_hits"; awk '{print $1}' "$domain" | sort | uniq -c | sort -rn | awk '{print "   " $2 ": " $1}'; requests=$(wc -l < "$domain"); bots=$(grep -ic bot "$domain"); xmlrpc=$(grep -ic xmlrpc "$domain"); echo -e "Page Requests: $requests\nBot Requests: $bots\nXML-RPC Requests: $xmlrpc\n-----------------------------"; done | sort -k3 -nr
